com.mirth.connect.plugins.javascriptstep.script:
logger.info('[CHANNEL: '+ channelName +'  Lookup Manager Loader starts ');
try {
    var datalakeApiUrl = LookupHelper.get("Config", "TECHBD_DEFAULT_DATALAKE_API_URL");

    if (!datalakeApiUrl || datalakeApiUrl.trim() === "") {
        throw "Lookup Manager configuration for DataLake API URL returned empty.";
    }

    channelMap.put("DATALAKE_API_URL", datalakeApiUrl);
    globalMap.put("datalakeApiUrl", datalakeApiUrl);
    logger.info("Datalake API URL loaded from Lookup Manager(config)");

} catch (e) {
    logger.error("Error fetching Datalake API URL: " + e);
    setErrorResponse(500, "Failed to load Datalake API URL");
    throw e;
}

/********************************************
    FETCH DEFAULT DATALAKE API URL (Plain text)
    WITH HEADER OVERRIDE SUPPORT
********************************************/

// First, check if the header override is provided
var headerDataLakeApiUrl = $('headers').getHeader('X-TechBD-DataLake-API-URL');

if (headerDataLakeApiUrl && String(headerDataLakeApiUrl).trim() !== "") {
   // Header provided - use it as override
   headerDataLakeApiUrl = headerDataLakeApiUrl.trim();
   channelMap.put("DATALAKE_API_URL", headerDataLakeApiUrl);
   globalMap.put("datalakeApiUrl", headerDataLakeApiUrl);
   logger.info("DataLake API URL overridden from request header: " + headerDataLakeApiUrl);
}
//////////////////////////////////////////////
/********************************************
    2️⃣ FETCH TECHBD_BL_BASEURL from header
********************************************/
// Capture TECHBD_BL_BASEURL from header if present
var techbdBlBaseUrl = "";
var incomingTechbdBlBaseUrl = $('headers').getHeader('X-TechBD-BL-BaseURL');

if (incomingTechbdBlBaseUrl != null && incomingTechbdBlBaseUrl.trim() !== '') {
    techbdBlBaseUrl = incomingTechbdBlBaseUrl.trim();
}
logger.info("TECHBD_BL_BASEURL from header: " + techbdBlBaseUrl);
channelMap.put("techbdBlBaseUrl", techbdBlBaseUrl);

/********************************************
    2️⃣ FETCH CSV SERVICE API URL (Plain text)
********************************************/
try {
    var csvServiceUrl = LookupHelper.get("Config", "TECHBD_CSV_SERVICE_API_URL");

    if (!csvServiceUrl || csvServiceUrl.trim() === "") {
        throw "AWS Secret for CSV Service URL returned empty.";
    }

    channelMap.put("CSV_SERVICE_API_URL", csvServiceUrl);
    globalMap.put("csvServiceApiUrl", csvServiceUrl);
    logger.info("CSV Service API URL loaded from Lookup Manager" + csvServiceUrl);

} catch (e) {
    logger.error("Error fetching CSV Service API URL: " + e);
    setErrorResponse(500, "Failed to load CSV Service API URL");
    throw e;
}


try {
    var validUrlsEnv = LookupHelper.get("Config", "MC_VALID_FHIR_URLS");
    if (!validUrlsEnv || validUrlsEnv.trim() === "") {
        throw "MC_VALID_FHIR_URLS is not configured in Lookup Manager";
    }
    channelMap.put("MC_VALID_FHIR_URLS", validUrlsEnv.trim());

    logger.info("Valid FHIR URLs loaded from Lookup Manager");
} catch (e) {
    logger.error("Error fetching valid FHIR URLs: " + e);
    setErrorResponse(500, "Failed to load valid FHIR URLs");
    throw e;
}


/********************************************
    9️⃣ FETCH DATA LEDGER  DATA_LEDGER_TRACKING (Plain text)
********************************************/

try {
    var dataLedgerTracking = LookupHelper.get("Config", "DATA_LEDGER_TRACKING");

    channelMap.put("DATA_LEDGER_TRACKING", dataLedgerTracking);
    globalMap.put("DATA_LEDGER_TRACKING", dataLedgerTracking);

    logger.info(" DataLedger Tracking loaded into channelMap"+ dataLedgerTracking);

} catch (e) {
    logger.error(" Error processing DataLedger Tracking secret: " + e.message);
}


/********************************************
    9️⃣ FETCH DATA LEDGER  DATA_LEDGER_DIAGNOSTICS (Plain text)
********************************************/

try {
    var dataLedgerDiagnostics = LookupHelper.get("Config", "DATA_LEDGER_DIAGNOSTICS");

    channelMap.put("DATA_LEDGER_DIAGNOSTICS", dataLedgerDiagnostics);
    globalMap.put("DATA_LEDGER_DIAGNOSTICS", dataLedgerDiagnostics);

    logger.info(" DataLedger diagnostics loaded into channelMap"+ dataLedgerDiagnostics);

} catch (e) {
    logger.error(" Error processing DataLedger diagnostics secret: " + e.message);
}

logger.info('[CHANNEL: '+ channelName +'  Lookup Manager Loader end ');

///////////////////////////////////////////////////////////////////////////
// Access the required header values using getHeader method
var tenantId = $('headers').getHeader('X-TechBD-Tenant-ID');
channelMap.put('tenantId', tenantId);
var userAgent = $('headers').getHeader('User-Agent');
channelMap.put('userAgent', userAgent);
var headers = $('headers');
logger.info("[CHANNEL: "+ channelName +"] HEADERS OBJECT: " + $('headers'));

var requestedPath = sourceMap.get('contextPath');
channelMap.put("requestUri", requestedPath);


// Parse the incoming request (assumes multipart form data)
var rawData = connectorMessage.getRawData();

// Validate Content-Type header
var contentType = $('headers').getHeader('Content-Type');

if (contentType == null || String(contentType).trim() === '' ||
    contentType.toLowerCase().indexOf('multipart/form-data') === -1) {

    var errorResponse = "Bad Request: Content-Type must be 'multipart/form-data' with boundary details";
logger.error("[CHANNEL: " + channelName + "] Missing or invalid Content-Type header: " + contentType);
setErrorResponse(400, errorResponse);
throw "Bad Request: Content-Type must be 'multipart/form-data' with boundary details";
}

// Check if rawData is empty
if (!rawData || rawData.trim().length == 0 || rawData.trim() == '') {
    errorMessage = "Uploaded file is empty or missing.";
    logger.info("[CHANNEL: "+ channelName +"] " + errorMessage);
    setErrorResponse(400, errorMessage);
    throw errorMessage;
}


// Read Base FHIR URL header
var customBaseFhirUrl = $('headers').getHeader('X-TechBD-Base-FHIR-URL');
    logger.info("X-TechBD-Base-FHIR-URL: " + customBaseFhirUrl);
    var validUrlsEnv = LookupHelper.get("Config", "MC_VALID_FHIR_URLS");
    logger.info("MC_VALID_FHIR_URLS from LookupHelper: " + validUrlsEnv);
    // Convert VALID_URLS to an array for validation
    var validUrls = validUrlsEnv ? validUrlsEnv.split(",").map(function(url) { return url.trim(); }) : [];
    if (customBaseFhirUrl !== null && customBaseFhirUrl.trim() != "") {

    if (validUrls.includes(customBaseFhirUrl)) {

    channelMap.put('TechBdBaseFhirurl',customBaseFhirUrl);    channelMap.put('baseFhirurl', customBaseFhirUrl);  
   } else {   		logger.info("ERROR");
			var errorMessage = 'The provided X-TechBD-Base-FHIR-URL is invalid. Base-FHIR-URL taken from the environment variable.';
			logger.error(errorMessage);
   }
    }

    
//Check the file type, only .zip is allowed
var filename = null;
var filenameMatch = rawData.match(/filename="([^"]+)"/); 

if (filenameMatch && filenameMatch.length > 1) {
    filename = filenameMatch[1];
    logger.info("Filename: " + filename);
    channelMap.put('filename', filename);
	logger.info("[CHANNEL: "+ channelName +"] filename " + filename);
    var extensionMatch = filename.match(/\.([0-9a-z]+)$/i);
    var extension = extensionMatch ? extensionMatch[1].toLowerCase().trim() : null;
    logger.info("File extension: " + extension);

    if (extension !== "zip" ) {
       var errorMessage = "Unsupported file extension: " + extension + ". Only .zip is allowed.";
       setErrorResponse(400, errorMessage); 
    	  throw errorMessage; 
    }
} else {
    logger.warn("Filename not found in message content.");
    errorMessage = "Uploaded file is empty or missing.";
    setErrorResponse(400, errorMessage);
    throw errorMessage;
}


// Check if the tenant is null or empty
if (tenantId == null || String(tenantId).trim() === "") {
    var errorMessage = 'Bad Request: Missing required header X-TechBD-Tenant-ID';
    setErrorResponse(400, errorMessage); 
    throw errorMessage;
}

///////////////////////////////////////////////////////////////////////////
// Parse the incoming request (assumes multipart form data)
var rawData = connectorMessage.getRawData();

// Check if rawData is empty
if (!rawData || rawData.trim().length === 0) {
    errorMessage = "No file provided in the request.";
    setErrorResponse(400, errorMessage); 
    throw errorMessage;
}

// -----------------------------------------------------
// Multiple multipart / multiple file validation
// -----------------------------------------------------
var partMatches = rawData.match(/Content-Disposition:/g) || [];
var fileMatches = rawData.match(/filename="/g) || [];

// If more than one multipart section
if (partMatches.length > 1) {
    var errorMessage = "Multiple parts detected in upload. Only one file is allowed.";
    logger.error(errorMessage);
    setErrorResponse(400, errorMessage);
    throw errorMessage;
}

// If more than one file
if (fileMatches.length > 1) {
    var errorMessage = "Multiple files detected in upload. Only one file is allowed.";
    logger.error(errorMessage);
    setErrorResponse(400, errorMessage);
    throw errorMessage;
}


// Parse the rawData as multipart form data
var boundary = rawData.split("\r\n")[0];
var parts = rawData.split(boundary);

// Initialize variables to store file content
var fileContent = null;

// Loop through parts to find the file part
var i = 0;
for each (var part in parts) {
    if (part.indexOf('Content-Disposition: form-data; name="file";') !== -1) {
        logger.info("[CHANNEL: "+ channelName +"] Part count " + ++i);
        // Extract the file content (skip headers)
        var contentStartIndex = part.indexOf("\r\n\r\n") + 4;
        fileContent = part.substring(contentStartIndex, part.lastIndexOf("\r\n"));
        break;
    }
}

// Validate the file content
if (!fileContent || fileContent == '' || fileContent.trim().length === 0) {
    errorMessage = "Uploaded file is empty or missing.";
    setErrorResponse(400, errorMessage);
    throw errorMessage;
}
///////////////////////////////////////////////////////////////////////////


///////////////////////////////////////////////////////////////////////////
// Validate ZIP content - must contain at least one CSV file

var ByteArrayInputStream = Packages.java.io.ByteArrayInputStream;
var ZipInputStream = Packages.java.util.zip.ZipInputStream;
var StandardCharsets = Packages.java.nio.charset.StandardCharsets;

var zipBytes;
var hasCsvFile = false;
var hasAnyFile = false;

try {

    zipBytes = fileContent.getBytes(StandardCharsets.ISO_8859_1);
    var byteStream = new ByteArrayInputStream(zipBytes);
    var zipStream = new ZipInputStream(byteStream);

    var entry;

    while ((entry = zipStream.getNextEntry()) != null) {

        logger.info("[CHANNEL: " + channelName + "] ZIP entry found: " + entry.getName());

        if (!entry.isDirectory()) {
            hasAnyFile = true;

            if (entry.getName().toLowerCase().endsWith(".csv")) {
                hasCsvFile = true;
            }
        }
    }

    zipStream.close();

} catch (e) {

    var errorMessage = "Invalid ZIP file or corrupted content.";
    logger.error(errorMessage + " " + e);
    setErrorResponse(400, errorMessage);
    throw errorMessage;
}



if (!hasAnyFile) {
    var errorMessage = "Bad Request: ZIP file contains no files (empty folders are not allowed).";
    logger.error(errorMessage);
    setErrorResponse(400, errorMessage);
    throw errorMessage;
}

if (!hasCsvFile) {
    var errorMessage = "Bad Request: ZIP file must contain at least one CSV file.";
    logger.error(errorMessage);
    setErrorResponse(400, errorMessage);
    throw errorMessage;
}
///////////////////////////////////////////////////////////////////////////

/* ----------------- Compact SimpleMultipartFile (in-memory) ----------------- */
function SimpleMultipartFile(originalFilename, contentType, contentBytes) {
    this.originalFilename = originalFilename;
    this.contentType = contentType || null;
    this.content = contentBytes || null;
}
SimpleMultipartFile.prototype.getName = function () { return this.originalFilename; };
SimpleMultipartFile.prototype.getOriginalFilename = function () { return this.originalFilename; };
SimpleMultipartFile.prototype.getContentType = function () { return this.contentType; };
SimpleMultipartFile.prototype.isEmpty = function () { return this.content == null || this.content.length == 0; };
SimpleMultipartFile.prototype.getSize = function () { return this.content ? this.content.length : 0; };
SimpleMultipartFile.prototype.getBytes = function () { return this.content; };
SimpleMultipartFile.prototype.getInputStream = function () {
    return new java.io.ByteArrayInputStream(this.content);
};

/* ----------------- 1. Read raw body ----------------- */
var bodyStr = connectorMessage.getRawData();

/* ----------------- 2. Detect boundary line ----------------- */
var nlPos = bodyStr.indexOf('\r\n');
var newlineLen = 2;
if (nlPos < 0) { nlPos = bodyStr.indexOf('\n'); newlineLen = 1; }
if (nlPos < 0) { throw 'No newline in body, cannot detect boundary'; }
var dashBoundary = bodyStr.substring(0, nlPos);
if (!dashBoundary.startsWith('--')) { throw 'Boundary line invalid: ' + dashBoundary; }
var boundary = dashBoundary.substring(2);

/* ----------------- 3. Convert to ISO-8859-1 ----------------- */
var bodyIso = new java.lang.String(bodyStr.getBytes('ISO-8859-1'), 'ISO-8859-1');

/* ----------------- 4. Locate file part ----------------- */
var dispIdx = bodyIso.indexOf('Content-Disposition: form-data; name="file"');
if (dispIdx < 0) throw 'Multipart section "file" not found';
var hdrEnd = bodyIso.indexOf('\r\n\r\n', dispIdx);
if (hdrEnd < 0) { hdrEnd = bodyIso.indexOf('\n\n', dispIdx); if (hdrEnd < 0) throw 'Malformed header'; }

/* ----------------- 5. Extract filename ----------------- */
var dispLineStart = bodyIso.lastIndexOf('Content-Disposition', hdrEnd);
var filenameMatch = bodyIso.substring(dispLineStart, hdrEnd).match(/filename="([^"]+)"/);
var filename = (filenameMatch && filenameMatch.length > 1) ? filenameMatch[1] : 'uploaded-file.zip';
filename = filename.trim().replace(/^.*[\/\\]/, '').replace(/[^\w\-.]/g, '_');

/* ----------------- 6. Extract file bytes ----------------- */
var dataStart = hdrEnd + (bodyIso.charAt(hdrEnd) == '\r' ? 4 : 2);
if (bodyIso.substring(dataStart, dataStart+2) == '\r\n') dataStart += 2;
else if (bodyIso.charAt(dataStart) == '\n') dataStart += 1;

var nextBndIdx = bodyIso.indexOf('\r\n--' + boundary, dataStart);
if (nextBndIdx < 0) nextBndIdx = bodyIso.indexOf('\n--' + boundary, dataStart);
if (nextBndIdx < 0) throw 'Closing boundary not found';
var dataEnd = nextBndIdx;
if (bodyIso.substring(dataEnd-2, dataEnd) == '\r\n') dataEnd -= 2;
else if (bodyIso.substring(dataEnd-1, dataEnd) == '\n') dataEnd -= 1;

var attachmentBytes = bodyIso.substring(dataStart, dataEnd).getBytes('ISO-8859-1');
logger.info('[CHANNEL: '+ channelName +'] Recovered ZIP length: ' + attachmentBytes.length);

/* ----------------- 7. Wrap in SimpleMultipartFile (optional) ----------------- */
var multipartFile = new SimpleMultipartFile(filename, 'application/zip', attachmentBytes);


/* ----------------- 8. Build multipart/form-data body ----------------- */

var uuid = generateUuid();
logger.info("Generated UUID v7: " + uuid);
var multipartBoundary = "----MirthBoundary" + uuid;
var header = "--" + multipartBoundary + "\r\n" +
             'Content-Disposition: form-data; name="file"; filename="' + filename + '"\r\n' +
             "Content-Type: application/zip\r\n\r\n";
var footer = "\r\n--" + multipartBoundary + "--\r\n";

var baos = new java.io.ByteArrayOutputStream();
baos.write(new java.lang.String(header).getBytes("UTF-8"));
baos.write(attachmentBytes);
baos.write(new java.lang.String(footer).getBytes("UTF-8"));
var fullBodyBytes = baos.toByteArray();
baos.close();

// Base64 encode for channelMap
var base64Body = Packages.java.util.Base64.getEncoder().encodeToString(fullBodyBytes);

channelMap.put("multipartBodyBase64", base64Body);
channelMap.put("multipartBoundary", multipartBoundary);
channelMap.put("multipartFileName", filename);
channelMap.put("multipartContentType", "application/zip");

logger.info("[CHANNEL: "+ channelName +"] Prepared multipart/form-data for destination, size: " + fullBodyBytes.length);

com.mirth.connect.plugins.javascriptrule.script:
var httpMethod = String(sourceMap.get('method')).toUpperCase();
var contextPath = String(connectorMessage.getSourceMap().get('contextPath')).replace(/\/$/, '');
//logger.info("HTTP Method: " + httpMethod);
//logger.info("Context Path: " + contextPath);

/**
 * Util function to generate JSON string
 */
function createJsonResponse(status, message) {
    return JSON.stringify({ status: status, message: message });
}

/**
 * Util function to set error response
 */
function setErrorResponse(statusCode, errorMessage) {
    responseMap.put('status', String(statusCode));
    responseMap.put('message', errorMessage);
    responseMap.put('fhirResponse', createJsonResponse(statusCode, errorMessage));
}

/* =====================================
   1️⃣ ROOT ENDPOINT
===================================== */
if (contextPath === '') {

   if (httpMethod === 'GET') {

    responseMap.put('responseStatusCode', 200);
    responseMap.put('responseContentType', 'application/json');
    responseMap.put('responseBody', JSON.stringify({
        status: 200,
        message: "OK"
    }));

   return false;
}

    // Method not allowed for /
    return methodNotAllowed();
}

/* =====================================
   2️⃣ HEALTHCHECK

===================================== */
if (contextPath === '/healthcheck') {

    if (httpMethod === 'GET') {
         responseMap.put('responseStatusCode', 200);
	    responseMap.put('responseContentType', 'application/json');
	    responseMap.put('responseBody', JSON.stringify({
	        status: 200,
	        message: "OK"
	    }));

	   return false;
    }

    return methodNotAllowed();
}

/* =====================================
   3️⃣ CSV BUNDLE
===================================== */
if (contextPath === '/flatfile/csv/Bundle' || contextPath === '/flatfile/csv/Bundle/' || contextPath === '/flatfile/csv/Bundle/$validate' || contextPath === '/flatfile/csv/Bundle/$validate/') {

    if (httpMethod === 'POST' || httpMethod === 'OPTIONS') {
        return true;
    }

    return methodNotAllowed();
}

/* =====================================
   ❌ INVALID PATH → 404
===================================== */
return notFound();




/* =====================================
   Helper Functions
===================================== */

function methodNotAllowed() {

    var errorResponse = "Method Not Allowed.";

    responseMap.put('responseStatusCode', 405);
    responseMap.put('responseContentType', 'application/json');
    responseMap.put('responseBody', JSON.stringify(errorResponse));

    setErrorResponse(405, errorResponse);

    throw "Invalid method";
}

function notFound() {

    var errorResponse = "Not Found: Invalid endpoint.";

    responseMap.put('responseStatusCode', 404);
    responseMap.put('responseContentType', 'application/json');
    responseMap.put('responseBody', JSON.stringify(errorResponse));

    setErrorResponse(404, errorResponse);

    throw "Invalid endpoint";
}

properties.script:
 /**
 * Destination JavaScript Writer:
 * Sends the uploaded ZIP file to the FHIR validate endpoint
 * using Apache HttpClient (DefaultHttpClient for Mirth compatibility)
 */
// --- Retrieve data from channelMap ---
var requestedPath = channelMap.get("requestUri");

var attachmentBytes = Packages.java.util.Base64.getDecoder().decode(channelMap.get('multipartBodyBase64'));
var filename = channelMap.get('multipartFileName') || 'uploaded-file.zip';
var tenantId = channelMap.get('tenantId') || 'defaultTenant';
var userAgent = channelMap.get('userAgent') || 'MirthConnector/1.0';
var sourceParam = 'CSV';

var baseFhirurl =  channelMap.get('baseFhirurl'); logger.info("baseFhirurl" +baseFhirurl);var techBdBaseFhirUrl =  channelMap.get('TechBdBaseFhirurl'); logger.info("techBdBaseFhirUrl" +techBdBaseFhirUrl);

// Read 'immediate' parameter from request and default invalid values to true.
var immediateParamRaw = $('parameters').get('immediate');
var immediateParam = String(immediateParamRaw == null ? "true" : immediateParamRaw).trim();

var immediateParamNormalized = immediateParam.toLowerCase();

if (immediateParamNormalized === "false" || immediateParamNormalized === "no") {
    immediateParam = "false";
} else {
    immediateParam = "true";
}

var csvServiceApiUrl = channelMap.get('CSV_SERVICE_API_URL');
logger.info("csvServiceApiUrl:" + csvServiceApiUrl+":"+"immediateParam :"+ immediateParam);

// --- Build URL with query parameter ---
//var urlStr = "http://10.10.11.253:8082/flatfile/csv/Bundle/?source=" + encodeURIComponent(sourceParam) + "&immediate=" + encodeURIComponent(immediateParam);
//var urlStr = "https://nexus.csv.sandbox.techbd.org/flatfile/csv/Bundle/?source=" + encodeURIComponent(sourceParam) + "&immediate=" + encodeURIComponent(immediateParam);
//var urlStr = csvServiceApiUrl +"/flatfile/csv/Bundle/?source=" + encodeURIComponent(sourceParam) + "&immediate=" + encodeURIComponent(immediateParam);

var urlStr  = "";
urlStr = csvServiceApiUrl +requestedPath+"?source=" + encodeURIComponent(sourceParam) + "&immediate=" + encodeURIComponent(immediateParam);


// --- Import Apache HttpClient classes ---
var DefaultHttpClient = Packages.org.apache.http.impl.client.DefaultHttpClient;
var HttpPost = Packages.org.apache.http.client.methods.HttpPost;
var MultipartEntityBuilder = Packages.org.apache.http.entity.mime.MultipartEntityBuilder;
var ContentType = Packages.org.apache.http.entity.ContentType;
var BasicHeader = Packages.org.apache.http.message.BasicHeader;

// --- Create client and POST ---
var client = new DefaultHttpClient();
var post = new HttpPost(urlStr);

// --- Use the prebuilt multipart from the transformer ---
var fullBodyBytes = Packages.java.util.Base64.getDecoder().decode(channelMap.get('multipartBodyBase64'));
var boundary = String(channelMap.get('multipartBoundary'));

var ByteArrayEntity = Packages.org.apache.http.entity.ByteArrayEntity;
var entity = new ByteArrayEntity(fullBodyBytes);

// IMPORTANT: tell the server this is multipart with the same boundary you built
entity.setContentType("multipart/form-data; boundary=" + boundary);

post.setEntity(entity);

channelMap.put('uri', sourceMap.get('uri'));
var uri = channelMap.get('uri') || '/flatfile/csv/Bundle/';

var severityLevel = String($('headers').getHeader('X-TechBD-Validation-Severity-Level') || "").trim();
channelMap.put('SeverityLevel', severityLevel || "error");

var dataLakeApiUrl = channelMap.get('DATALAKE_API_URL');
var techbdBlBaseUrl = channelMap.get('techbdBlBaseUrl');
var dataLedgerTracking = channelMap.get('DATA_LEDGER_TRACKING');
var dataLedgerDiagnostics = channelMap.get('DATA_LEDGER_DIAGNOSTICS');
//logger.info("**************************techbdBlBaseUrl from channelMap: " + techbdBlBaseUrl);

// --- Set required headers ---
post.setHeader(new BasicHeader("Accept", "application/fhir+json"));
post.setHeader(new BasicHeader("X-TechBD-Tenant-ID", tenantId));
post.setHeader(new BasicHeader("User-Agent", userAgent));
post.setHeader(new BasicHeader("Access-Control-Allow-Origin", "*"));
post.setHeader(new BasicHeader("Access-Control-Allow-Methods", "GET, POST, OPTIONS"));
post.setHeader(new BasicHeader("Access-Control-Allow-Headers", "Content-Type, Authorization, X-TechBD-Base-FHIR-URL, X-TechBD-Tenant-ID, User-Agent, X-TechBD-REMOTE-IP, X-TechBD-Override-Request-URI, X-Correlation-ID, accept, X-TechBD-DataLake-API-URL, DataLake-API-Content-Type, X-TechBD-HealthCheck, X-TechBD-Validation-Severity-Level, X-SHIN-NY-IG-Version"));
post.setHeader(new BasicHeader("Access-Control-Allow-Credentials", "true"));
post.setHeader(new BasicHeader("X-TechBD-REMOTE-IP", uri));
post.setHeader(new BasicHeader("X-TechBD-Override-Request-URI", uri));
post.setHeader(new BasicHeader("X-TechBD-Request-URI", uri));
post.setHeader(new BasicHeader("X-TechBD-Validation-Severity-Level", severityLevel));
post.setHeader(new BasicHeader("X-TechBD-Source-Type", sourceParam));
post.setHeader(new BasicHeader("X-TechBD-Base-FHIR-URL", techBdBaseFhirUrl));
post.setHeader(new BasicHeader("X-TechBD-DataLake-API-URL", dataLakeApiUrl));
post.setHeader(new BasicHeader("X-TechBD-Data-Ledger-Tracking", dataLedgerTracking));
post.setHeader(new BasicHeader("X-TechBD-Data-Ledger-diagnostics", dataLedgerDiagnostics));
if (techbdBlBaseUrl != null && techbdBlBaseUrl !== '') {
    post.setHeader(new BasicHeader("X-TechBD-BL-BaseURL", techbdBlBaseUrl));
}

// --- Include additional headers from channelMap if any ---
var headerParameters = channelMap.get("headerParameters");
if (headerParameters != null) {
    var iter = headerParameters.entrySet().iterator();
    while (iter.hasNext()) {
        var entry = iter.next();
        post.setHeader(new BasicHeader(entry.getKey(), entry.getValue()));
    }
}

// --- Execute request ---
var response = client.execute(post);
var responseEntity = response.getEntity();
var responseCode = response.getStatusLine().getStatusCode();
var responseStr = "";

if (responseEntity != null) {
    var reader = new java.io.BufferedReader(new java.io.InputStreamReader(responseEntity.getContent(), "UTF-8"));
    var line;
    while ((line = reader.readLine()) != null) {
        responseStr += line;
    }
    reader.close();
}

// --- Log and store response in channelMap ---
logger.info("[CHANNEL: "+ channelName +"] FHIR validate response (" + responseCode + "): " + responseStr);
channelMap.put("fhirResponse", responseStr);
channelMap.put("fhirResponseCode", responseCode);

responseMap.put('fhirResponse', responseStr);

channel.postprocessingScript:
// This script executes once after a message has been processed
// Responses returned from here will be stored as "Postprocessor" in the response map
return;

channel.undeployScript:
// This script executes once when the channel is undeployed
// You only have access to the globalMap and globalChannelMap here to persist data
return;

properties.code:
/**
	Util function to set error response.

	@param {Any} map - 
	@param {Any} statusCode - 
	@param {Any} errorMessage - 
	@return {Any} 
*/
function setErrorResponse(statusCode, errorMessage, map) {
    var targetMap = map || responseMap;

    var json = createJsonResponse(statusCode, errorMessage);
    targetMap.put('status', String(statusCode));
    targetMap.put('responseStatusCode', statusCode);
    targetMap.put('fhirResponse', json);
}
/**
 Util function to generate json string wit hstatus and message
*/
function createJsonResponse(status, message) {
    return JSON.stringify({ status: status, message: message });
}

function getUuidGenerator() {
    var generator = globalMap.get('UUID_GENERATOR');

    if (generator == null) {
        var Generators = Packages.com.fasterxml.uuid.Generators;
        generator = Generators.timeBasedEpochGenerator();

        globalMap.put('UUID_GENERATOR', generator);
        logger.info('UUID Generator initialized ONCE');
    }

    return generator;
}

function generateUuid() {
    return getUuidGenerator().generate().toString();
}
